import { AbiCoder, keccak256, toUtf8Bytes } from 'ethers';

interface DecodedSwap {
  amount0: bigint;
  amount1: bigint;
  sqrtPriceX96: bigint;
  liquidity: bigint;
  tick: number;
}

const SWAP_TOPIC = keccak256(toUtf8Bytes(
  'Swap(address,address,int256,int256,uint160,uint128,int24)'
));

export function decodeSwapEvent(log: {
  topics: string[];
  data: string;
}): DecodedSwap {
  if (log.topics[0] !== SWAP_TOPIC) {
    throw new Error(`Not a Swap event: topic0=${log.topics[0]?.slice(0, 10)}`);
  }
  if (log.data.length < 2 + 64 * 5) {
    throw new Error(`Malformed log data: expected 320 bytes, got ${(log.data.length - 2) / 2}`);
  }

  const coder = AbiCoder.defaultAbiCoder();
  const decoded = coder.decode(
    ['int256', 'int256', 'uint160', 'uint128', 'int24'],
    log.data,
  );

  return {
    amount0: decoded[0],
    amount1: decoded[1],
    sqrtPriceX96: decoded[2],
    liquidity: decoded[3],
    tick: Number(decoded[4]),
  };
}
