use rlp::{Rlp, DecoderError};
use ethereum_types::{H160, H256, U256};

#[derive(Debug)]
pub struct ParsedTx {
    pub nonce: U256,
    pub gas_price: U256,
    pub gas_limit: U256,
    pub to: Option<H160>,
    pub value: U256,
    pub data: Vec<u8>,
    pub v: u64,
    pub r: H256,
    pub s: H256,
}

pub fn parse_legacy_tx(raw: &[u8]) -> Result<ParsedTx, String> {
    let rlp = Rlp::new(raw);
    if rlp.item_count().map_err(|e| format!("RLP error: {e}"))? != 9 {
        return Err(format!("Expected 9 RLP items for legacy tx, got {}",
            rlp.item_count().unwrap_or(0)));
    }

    let to_bytes: Vec<u8> = rlp.val_at(3).map_err(|e| format!("'to' field: {e}"))?;
    let to = if to_bytes.is_empty() { None } else {
        if to_bytes.len() != 20 {
            return Err(format!("'to' must be 20 bytes, got {}", to_bytes.len()));
        }
        Some(H160::from_slice(&to_bytes))
    };

    Ok(ParsedTx {
        nonce: rlp.val_at(0).map_err(|e| format!("nonce: {e}"))?,
        gas_price: rlp.val_at(1).map_err(|e| format!("gas_price: {e}"))?,
        gas_limit: rlp.val_at(2).map_err(|e| format!("gas_limit: {e}"))?,
        to,
        value: rlp.val_at(4).map_err(|e| format!("value: {e}"))?,
        data: rlp.val_at(5).map_err(|e| format!("data: {e}"))?,
        v: rlp.val_at(6).map_err(|e| format!("v: {e}"))?,
        r: rlp.val_at(7).map_err(|e| format!("r: {e}"))?,
        s: rlp.val_at(8).map_err(|e| format!("s: {e}"))?,
    })
}
